  *
  * OVERVIEW FOR BEGINNERS:
  * ========================
  * This file is the very first code that runs when your STM32 microcontroller
  * powers on or resets. Before your C code (main()) can run, several things
  * must be set up at the hardware level. This file does those things:
  *
  *   1. Sets up the stack pointer (where function call data lives in RAM)
  *   2. Copies initialized global variables from Flash (permanent storage)
  *      into RAM (working memory), because RAM loses its contents on power loss
  *   3. Zeroes out uninitialized global variables (the BSS segment)
  *   4. Calls SystemInit() to configure clocks
  *   5. Calls __libc_init_array() to run C++ static constructors
  *   6. Jumps to your main() function
  *
  * It also defines the "vector table" — a lookup table of function pointers
  * that tells the hardware WHERE to jump when an interrupt or exception fires.
  *
  * This file is written in ARM Thumb assembly. You don't need to edit it
  * unless you are doing very low-level customization.
  */

/* ============================================================================
 * ASSEMBLER DIRECTIVES
 * These are instructions TO the assembler (the program that converts this
 * text into machine code), not instructions that run on the chip itself.
 * ============================================================================ */

.syntax unified      /* Use "unified" ARM/Thumb syntax — a modern syntax that
                        lets you write both ARM and Thumb instructions the
                        same way, instead of having two different styles. */

.cpu cortex-m4       /* Tell the assembler we're targeting the ARM Cortex-M4
                        core inside the STM32F407. This enables Cortex-M4
                        specific instructions. */

.fpu softvfp         /* "softvfp" = software floating point ABI with hardware
                        FPU registers. This means: use the hardware FPU unit
                        for calculations, but pass float arguments through
                        integer registers when calling functions.
                        The alternative is "hard" (hardfp) which passes floats
                        directly in FPU registers — slightly faster but
                        requires all libraries to be compiled the same way. */

.thumb               /* Generate Thumb-2 instructions (16/32-bit compact
                        encoding) rather than full 32-bit ARM instructions.
                        Cortex-M4 ONLY runs Thumb mode — it cannot execute
                        classic 32-bit ARM instructions at all. */

/* ============================================================================
 * GLOBAL SYMBOL EXPORTS
 * These lines make these two symbols visible to the linker and other files.
 * Without .global, a symbol is private to this file.
 * ============================================================================ */

.global g_pfnVectors   /* The interrupt vector table (defined later in this
                          file). The linker needs to find it to place it at
                          address 0x00000000 in Flash. */

.global Default_Handler /* A catch-all handler for any interrupt that doesn't
                           have a real implementation written yet. */

/* ============================================================================
 * LINKER SCRIPT SYMBOL REFERENCES
 * The .word directive places a 32-bit address literal into the output binary.
 * These symbols (starting with underscore) are NOT defined here — they are
 * defined in the linker script (.ld file) which knows the exact memory map
 * of this chip. The linker will fill in the actual addresses at link time.
 *
 * Think of this like declaring "extern" variables in C: we're telling the
 * assembler "these addresses exist somewhere, the linker will resolve them."
 * ============================================================================ */

.word _sidata  /* Source address in Flash where the initial values of
                  initialized global variables are stored.
                  ("si" = source of initialized data) */

.word _sdata   /* Start address in RAM where .data section begins.
                  ("s" = start, "data" = initialized globals/statics) */

.word _edata   /* End address in RAM where .data section ends.
                  ("e" = end) */

.word _sbss    /* Start address in RAM of the .bss section.
                  BSS = Block Started by Symbol — this is where uninitialized
                  global and static variables live. C standard says they must
                  start as zero, so we'll zero this region out explicitly. */

.word _ebss    /* End address in RAM of the .bss section. */


/* ============================================================================
 * RESET HANDLER
 * ============================================================================
 *
 * This is the entry point of your entire program. When the chip powers on
 * or is reset, the hardware automatically:
 *   1. Reads address 0x00000000 → loads it into the Stack Pointer (SP)
 *   2. Reads address 0x00000004 → loads it into the Program Counter (PC)
 *
 * Address 0x00000004 in the vector table contains the address of
 * Reset_Handler, so execution jumps here immediately after reset.
 *
 * .section .text.Reset_Handler
 *   Put this code in a special named section so the linker can place it
 *   correctly. The linker script will pull this into the .text region of Flash.
 *
 * .weak Reset_Handler
 *   "Weak" means: if another file defines a symbol with this same name,
 *   use that one instead and discard this one. This lets application code
 *   override the default startup behavior if needed.
 *
 * .type Reset_Handler, %function
 *   Tells the assembler (and debugger) that this symbol is a function,
 *   not just a data label. Important for correct stack unwinding in debuggers.
 */

  .section .text.Reset_Handler
  .weak Reset_Handler
  .type Reset_Handler, %function

Reset_Handler:

  /* --- Step 1: Initialize the Stack Pointer ---
   *
   * The stack is a region of RAM used to store:
   *   - Return addresses when calling functions
   *   - Local variables
   *   - Saved register values during interrupts
   *
   * On Cortex-M, the stack grows DOWNWARD in memory (from high address to low).
   * _estack is defined in the linker script as the TOP of RAM (highest address).
   * We load this address into SP (Stack Pointer register, also called r13).
   *
   * "ldr r0, =_estack" is a pseudo-instruction. The assembler generates a
   * PC-relative load from a literal pool — it's loading the 32-bit address
   * value of _estack into register r0.
   *
   * "mov sp, r0" copies that value into the actual Stack Pointer register.
   *
   * After this, any function call or interrupt will use this stack correctly.
   */
  ldr   r0, =_estack
  mov   sp, r0


  /* --- Step 2: Copy .data section from Flash to RAM ---
   *
   * WHY IS THIS NECESSARY?
   * Flash memory retains its contents when power is removed, but it's
   * read-only at runtime (you can't write to Flash during normal execution
   * without a special erase/write procedure). RAM is fast and writable,
   * but loses everything on power-off.
   *
   * When you write C code like:
   *     int myGlobal = 42;   // initialized global variable
   *
   * The value 42 must be stored somewhere permanently (Flash), but the
   * variable itself must live in RAM so it can be modified. The linker puts
   * the initial value (42) into a Flash region called .sidata, and reserves
   * a slot in RAM called .data. This startup code copies from .sidata → .data
   * before main() runs, so your globals have their correct initial values.
   *
   * The copy loop below:
   *   r0 = destination start (RAM: _sdata)
   *   r1 = destination end   (RAM: _edata)
   *   r2 = source start      (Flash: _sidata)
   *   r3 = byte offset counter (starts at 0, increments by 4 each iteration)
   *
   * We jump to LoopCopyDataInit first to check whether there's anything
   * to copy at all (handles the edge case of an empty .data section).
   */
  ldr r0, =_sdata    /* Load address of start of .data section in RAM */
  ldr r1, =_edata    /* Load address of end of .data section in RAM */
  ldr r2, =_sidata   /* Load address of initial values stored in Flash */
  movs r3, #0        /* r3 = 0 (byte offset, starts at beginning) */
  b LoopCopyDataInit /* Jump to the loop condition check first */

CopyDataInit:
  /* Loop body: copy one 32-bit word (4 bytes) per iteration */
  ldr r4, [r2, r3]   /* Load 4 bytes from Flash: address = r2 + r3 offset */
  str r4, [r0, r3]   /* Store those 4 bytes to RAM:  address = r0 + r3 offset */
  adds r3, r3, #4    /* Advance offset by 4 bytes (one word) */
                     /* "adds" sets condition flags (N, Z, C, V) — needed by bcc below */

LoopCopyDataInit:
  /* Loop condition: check if we've reached the end of .data */
  adds r4, r0, r3    /* r4 = current destination address (RAM base + offset) */
  cmp r4, r1         /* Compare current address against end-of-.data (_edata) */
  bcc CopyDataInit   /* BCC = Branch if Carry Clear = Branch if r4 < r1
                        i.e., loop back if we haven't reached the end yet.
                        When r4 >= r1, we fall through and the copy is done. */


  /* --- Step 3: Zero-fill the .bss section in RAM ---
   *
   * WHY IS THIS NECESSARY?
   * The C standard guarantees that uninitialized global and static variables
   * start at zero. For example:
   *     int counter;           // uninitialized global — must start as 0
   *     static int flag;       // uninitialized static — must start as 0
   *
   * The linker places these in a section called .bss (historically "Block
   * Started by Symbol"). Nothing is stored in Flash for .bss (there are no
   * initial values to store — they're all zero). We just need to zero out
   * that RAM region ourselves before main() runs.
   *
   * r2 = current address being zeroed (starts at _sbss)
   * r4 = end address (_ebss)
   * r3 = the value 0 (what we're writing)
   *
   * Same pattern as above: jump to condition check first.
   */
  ldr r2, =_sbss     /* Load start address of .bss in RAM */
  ldr r4, =_ebss     /* Load end address of .bss in RAM */
  movs r3, #0        /* r3 = 0 (the value to write everywhere) */
  b LoopFillZerobss  /* Jump to condition check first */

FillZerobss:
  /* Loop body: write one 32-bit zero per iteration */
  str  r3, [r2]      /* Store 0 into current address (r2 points to RAM) */
  adds r2, r2, #4    /* Advance pointer by 4 bytes */

LoopFillZerobss:
  /* Loop condition: have we zeroed everything up to _ebss? */
  cmp r2, r4         /* Compare current pointer against end of .bss */
  bcc FillZerobss    /* Loop back if r2 < r4 (not done yet) */


  /* --- Step 4: Initialize the system clock ---
   *
   * SystemInit() is a function provided by ST's CMSIS/HAL library (in
   * system_stm32f4xx.c). It configures the PLL (Phase-Locked Loop) and
   * clock prescalers to run the chip at its target frequency (up to 168 MHz
   * on the F407). Without this call, the chip runs from the slow internal
   * RC oscillator at 16 MHz with no PLL.
   *
   * "bl" = Branch with Link. It calls the function AND saves the return
   * address in the Link Register (LR / r14), so the function can return
   * here with "bx lr".
   */
  bl  SystemInit


  /* --- Step 5: Run C++ static constructors ---
   *
   * __libc_init_array() is part of the C runtime library (newlib).
   * It iterates over the .init_array section in Flash and calls every
   * function pointer stored there. The compiler places constructors for
   * global C++ objects there, as well as any functions marked with
   * __attribute__((constructor)) in C.
   *
   * If you're writing pure C with no global objects, this effectively does
   * nothing — but it's safe and correct to always call it.
   */
  bl __libc_init_array


  /* --- Step 6: Call main() ---
   *
   * Everything is now set up. Jump to the user's application entry point.
   * "bl main" is technically a function call (saves return address in LR),
   * which is correct — main() could theoretically return, though on a
   * bare-metal embedded system it normally never does.
   */
  bl main


  /* --- Step 7: Trap if main() ever returns ---
   *
   * On an embedded system, main() returning is almost always a bug —
   * there's nowhere sensible to go back to. This infinite loop prevents
   * the program counter from wandering into random memory and executing
   * garbage instructions, which could cause unpredictable hardware behavior.
   *
   * A debugger can detect the chip is stuck here by examining the PC register.
   */
LoopForever:
    b LoopForever     /* "b" = unconditional Branch — jumps back to itself forever */


  /* Tell the assembler the size of Reset_Handler (used by debuggers for
     stack unwinding and function boundary detection).
     "." means "current address", so this computes: current_addr - Reset_Handler_start */
  .size Reset_Handler, .-Reset_Handler


/* ============================================================================
 * DEFAULT INTERRUPT HANDLER
 * ============================================================================
 *
 * If an interrupt fires but no specific handler function has been written
 * for it, the weak alias mechanism (defined at the bottom of this file)
 * redirects it here. This handler just spins forever in an infinite loop.
 *
 * In practice, if you hit this handler unexpectedly, it means:
 *   - An interrupt was enabled that you forgot to write a handler for
 *   - An interrupt fired due to a hardware misconfiguration or a bug
 *
 * When debugging, you can set a breakpoint here to catch unexpected interrupts.
 * Then examine the stack and LR register to figure out which interrupt fired.
 *
 * "ax" in the .section directive means:
 *   a = allocatable (takes up space in the binary)
 *   x = executable (contains instructions, not just data)
 * %progbits means it contains actual program data (not zero-fill like .bss)
 */
  .section .text.Default_Handler,"ax",%progbits
Default_Handler:
Infinite_Loop:
  b Infinite_Loop    /* Spin here forever. The system is in an unknown state.
                        A watchdog timer (if configured) will eventually reset
                        the chip and give it another chance to run correctly. */
  .size Default_Handler, .-Default_Handler


/* ============================================================================
 * INTERRUPT VECTOR TABLE
 * ============================================================================
 *
 * WHAT IS THE VECTOR TABLE?
 * On ARM Cortex-M, when an interrupt or exception occurs, the hardware
 * automatically looks up a table of function pointers stored at the very
 * beginning of Flash memory (address 0x00000000). Each slot in the table
 * corresponds to a specific exception or interrupt source. The hardware reads
 * the address stored in that slot and jumps to it — this is the "handler".
 *
 * The table MUST be placed at address 0x00000000 (or at a location pointed
 * to by the VTOR register — Vector Table Offset Register — if you move it).
 * The linker script uses the ".isr_vector" section name to ensure this.
 *
 * TABLE LAYOUT:
 * Slot 0:  Initial Stack Pointer value (not a function — it's loaded into SP at reset)
 * Slot 1:  Reset Handler address (where execution begins)
 * Slot 2+: Exception and interrupt handler addresses
 *
 * Each entry is a 32-bit address (.word = 4 bytes).
 * Entries that say "0" are "reserved" by ST — those interrupt numbers don't
 * exist on this chip, so the slot is left empty (null pointer).
 *
 * "a" in .section means allocatable (included in the binary output).
 * %progbits means it contains real data.
 */
  .section .isr_vector,"a",%progbits
  .type g_pfnVectors, %object
  .size g_pfnVectors, .-g_pfnVectors

g_pfnVectors:

  /* ---- ARM Cortex-M Core Exceptions (positions 0–15) ---- */
  /* These are defined by the ARM architecture itself, not ST.
     Every Cortex-M chip has these same first 16 entries. */

  .word _estack                /* [0] Initial stack pointer value.
                                    NOT a handler address — the hardware loads
                                    this directly into SP (r13) on reset.
                                    _estack is the top of RAM. */

  .word Reset_Handler          /* [1] Reset exception — runs on power-on/reset.
                                    This is the entry point defined above. */

  .word NMI_Handler            /* [2] Non-Maskable Interrupt — cannot be
                                    disabled by software. Used for critical
                                    faults like clock failure. */

  .word HardFault_Handler      /* [3] Hard Fault — fires when a fault occurs
                                    that has no more specific handler, or when
                                    a fault occurs inside another fault handler.
                                    Common causes: null pointer dereference,
                                    stack overflow, bad instruction. */

  .word MemManage_Handler      /* [4] Memory Management Fault — MPU (Memory
                                    Protection Unit) access violation. Fires
                                    when code tries to access memory it's not
                                    allowed to (e.g., executing from RAM when
                                    the MPU forbids it). */

  .word BusFault_Handler       /* [5] Bus Fault — error on the AHB/APB bus
                                    during a memory access. Can be caused by
                                    accessing a non-existent peripheral address
                                    or bad DMA configuration. */

  .word UsageFault_Handler     /* [6] Usage Fault — undefined instruction,
                                    illegal unaligned access, invalid state
                                    transition (e.g., trying to switch to
                                    ARM mode from Thumb-only Cortex-M). */

  .word 0                      /* [7] Reserved by ARM spec */
  .word 0                      /* [8] Reserved by ARM spec */
  .word 0                      /* [9] Reserved by ARM spec */
  .word 0                      /* [10] Reserved by ARM spec */

  .word SVC_Handler            /* [11] SVCall (Supervisor Call) — triggered by
                                    the "svc" instruction. Used by RTOS kernels
                                    (like FreeRTOS) to request privileged
                                    operations from unprivileged task code. */

  .word DebugMon_Handler       /* [12] Debug Monitor — fires when a software
                                    breakpoint or watchpoint is hit while the
                                    debug monitor is active (as opposed to
                                    being halted by a hardware debugger). */

  .word 0                      /* [13] Reserved by ARM spec */

  .word PendSV_Handler         /* [14] PendSV (Pendable Service Call) — a
                                    software-triggerable, low-priority interrupt.
