  .word SysTick_Handler        /* [15] SysTick — a simple 24-bit countdown
                                    timer built into the Cortex-M core.
                                    HAL uses this for the HAL_Delay() 1ms tick.
                                    FreeRTOS uses it for the scheduler tick. */


